function log(step, status, detail) {
  const line = { step, status, detail, ts: new Date().toISOString() };
  results.push(line);
  console.log(`[${status}] ${step}: ${typeof detail === 'string' ? detail : JSON.stringify(detail)}`);
}

// 1. Health check
try {
  const r = await fetch(`${API}/health`);
  const j = await r.json().catch(() => ({}));
  log('GET /health', r.status === 200 ? 'PASS' : 'FAIL', `HTTP ${r.status} commit=${j.commit || j.sha || 'n/a'} boot=${j.bootTime || j.boot || 'n/a'}`);
} catch (e) {
  log('GET /health', 'FAIL', String(e));
}

// 2. OPTIONS preflight
try {
  const r = await fetch(`${API}/api/ivx/owner-passwordless-login`, { method: 'OPTIONS' });
  log('OPTIONS /api/ivx/owner-passwordless-login', r.status === 204 || r.status === 200 ? 'PASS' : 'FAIL', `HTTP ${r.status}`);
} catch (e) {
  log('OPTIONS preflight', 'FAIL', String(e));
}

// 3. Real owner login (password grant server-side)
try {
  const r = await fetch(`${API}/api/ivx/owner-passwordless-login`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ email: OWNER_EMAIL }),
  });
  const j = await r.json().catch(() => ({}));
  const hasJwt = typeof j.accessToken === 'string' && j.accessToken.length > 20;
  const jwtSnippet = hasJwt ? `${j.accessToken.slice(0,20)}...${j.accessToken.slice(-12)}` : 'none';
  log('POST owner login (real email)', r.status === 200 && j.success ? 'PASS' : 'FAIL',
    `HTTP ${r.status} success=${j.success} userId=${j.userId || 'n/a'} email=${j.email || 'n/a'} accountType=owner passwordSelfHealed=${j.passwordSelfHealed} jwt=${jwtSnippet} expiresAtIso=${j.expiresAtIso || 'n/a'}`);

  // 3b. Verify the JWT is a real Supabase JWT by decoding the payload
  if (hasJwt) {
    try {
      const parts = j.accessToken.split('.');
      const payload = JSON.parse(Buffer.from(parts[1], 'base64').toString('utf8'));
      log('JWT payload decode', 'PASS', `sub=${payload.sub} email=${payload.email} role=${payload.role} aud=${payload.aud} exp=${new Date((payload.exp||0)*1000).toISOString()}`);
    } catch (e) {
      log('JWT payload decode', 'FAIL', String(e));
    }
  }
} catch (e) {
  log('POST owner login', 'FAIL', String(e));
}

// 4. Negative: no email
try {
  const r = await fetch(`${API}/api/ivx/owner-passwordless-login`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({}),
  });
  const j = await r.json().catch(() => ({}));
  log('POST no email (negative)', r.status === 400 ? 'PASS' : 'FAIL', `HTTP ${r.status} rootCause=${j.rootCause || 'n/a'}`);
} catch (e) {
  log('POST no email', 'FAIL', String(e));
}

// 5. Negative: non-allowlist email
try {
  const r = await fetch(`${API}/api/ivx/owner-passwordless-login`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ email: 'intruder@example.com' }),
  });
  const j = await r.json().catch(() => ({}));
  log('POST non-allowlist (negative)', r.status === 403 ? 'PASS' : 'FAIL', `HTTP ${r.status} rootCause=${j.rootCause || 'n/a'}`);
} catch (e) {
  log('POST non-allowlist', 'FAIL', String(e));
}

// Summary
const pass = results.filter(x => x.status === 'PASS').length;
const fail = results.filter(x => x.status === 'FAIL').length;
console.log('\n=== SUMMARY ===');
console.log(`PASS: ${pass} / FAIL: ${fail} / TOTAL: ${results.length}`);
const proof = {
  qaRun: new Date().toISOString(),
  endpoint: API,
  ownerEmail: OWNER_EMAIL,
  passwordConfigured: !!OWNER_PASSWORD,
  passwordLength: OWNER_PASSWORD ? OWNER_PASSWORD.length : 0,
  results,
  summary: { pass, fail, total: results.length, verified: fail === 0 },
};
console.log('\n=== PROOF JSON ===');
console.log(JSON.stringify(proof, null, 2));
EOF
node /tmp/owner-login-proof.mjs 2>&1"}

